#include <iostream>
#include <string>
#include <sstream>
#include <streambuf>

// Assumes the user's solution is encapsulated in a 'solve()' function.
// The 'main' function in the user's code should simply call 'solve()'.
std::string run_user_code(const std::string& input) {
    std::istringstream iss(input);
    std::streambuf* old_cin_buf = std::cin.rdbuf(iss.rdbuf());

    std::ostringstream oss;
    std::streambuf* old_cout_buf = std::cout.rdbuf(oss.rdbuf());

    solve(); 

    std::cin.rdbuf(old_cin_buf);
    std::cout.rdbuf(old_cout_buf);

    return oss.str();
}
